import{_ as t,o as r,c as a,ae as o}from"./chunks/framework.DAK3ioSj.js";const m=JSON.parse('{"title":"Hermes Agent Self-Evolution","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-hermes-self-evolution.md","filePath":"radar/tech-hermes-self-evolution.md"}'),l={name:"radar/tech-hermes-self-evolution.md"};function n(s,e,i,h,d,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="hermes-agent-self-evolution" tabindex="-1">Hermes Agent Self-Evolution <a class="header-anchor" href="#hermes-agent-self-evolution" aria-label="Permalink to &quot;Hermes Agent Self-Evolution&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 优化 / Skill 评测 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.70</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: Nous Research 的 Skill 自动进化引擎 —— <strong>GEPA 优化器</strong>（ICLR 2026 接收，Oral 状态以官方录用为准）+ 严格约束门控 + PR 模式人工审核。</p><p><strong>来源</strong>:</p><ul><li>工业 + 学术 - Nous Research</li><li>独立仓库架构（操作 hermes-agent 而非嵌入其中）</li></ul><p><strong>链接</strong>:</p><ul><li>自进化仓库：<a href="https://github.com/NousResearch/hermes-agent-self-evolution" target="_blank" rel="noreferrer">hermes-agent-self-evolution</a></li><li>主 Agent 仓库：<a href="https://github.com/NousResearch/hermes-agent" target="_blank" rel="noreferrer">hermes-agent</a>（<strong>145K+ ★</strong>）</li><li>自进化仓库本身：<strong>3.1K+ ★</strong></li><li><a href="https://github.com/NousResearch/hermes-agent-self-evolution/blob/main/PLAN.md" target="_blank" rel="noreferrer">PLAN.md 设计文档</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="gepa-优化器" tabindex="-1">GEPA 优化器 <a class="header-anchor" href="#gepa-优化器" aria-label="Permalink to &quot;GEPA 优化器&quot;">​</a></h3><p>不是简单试错 —— 读取执行轨迹<strong>理解&quot;为什么失败&quot;</strong>，然后提出针对性改进。</p><p><strong>例</strong>：GitHub PR 代码审查 Skill 在大 PR 上经常遗漏安全问题 → GEPA 分析轨迹发现&quot;Skill 没有指示 Agent 按文件类型分组审查&quot; → 生成改进版本加上这个指示。</p><p>基于 DSPy 框架，<strong>已被 ICLR 2026 接收</strong>（Oral 状态请以官方录用通知为准）。</p><h3 id="严格安全门控" tabindex="-1">严格安全门控 <a class="header-anchor" href="#严格安全门控" aria-label="Permalink to &quot;严格安全门控&quot;">​</a></h3><ul><li>每个进化变体<strong>必须通过完整测试套件</strong> —— 任何测试失败则变体被拒绝</li><li>严格的大小预算 —— 长度惩罚防止冗长漂移</li><li>最终以 <strong>PR 形式</strong>提交到 hermes-agent 仓库，带 diff 和 before/after 对比，由人类审核后合并</li></ul><h3 id="双数据源" tabindex="-1">双数据源 <a class="header-anchor" href="#双数据源" aria-label="Permalink to &quot;双数据源&quot;">​</a></h3><ul><li><strong>synthetic</strong> —— 合成评测数据</li><li><strong>sessiondb</strong> —— 真实会话历史（兼容 Claude Code / Copilot / Hermes）</li></ul><p>无 GPU 依赖，一切通过 API 调用完成文本级优化。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>紧密绑定 Hermes Agent 生态</li><li>进化结果需人工审核（PR 模式），非全自动部署</li><li>跨领域迁移未验证 —— &quot;从总结 GitHub PR 学到的 Skill 不能迁移到规划数据库迁移&quot;</li><li>测试套件本身不包含安全检查（约束门控只能拦截功能性退化）</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.65</td><td>已可工程使用，有完整 PLAN.md</td></tr><tr><td>创新性</td><td>0.85</td><td>GEPA 是 ICLR Oral 工作，方法论级突破</td></tr><tr><td>落地程度</td><td>0.55</td><td>Hermes 生态内已实用，跨平台未普及</td></tr><tr><td>生态活跃度</td><td>0.80</td><td>Nous 社区活跃，Hermes Agent 145K+ ★</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.70</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://github.com/NousResearch/hermes-agent-self-evolution" target="_blank" rel="noreferrer">hermes-agent-self-evolution GitHub</a></li><li><a href="https://github.com/NousResearch/hermes-agent" target="_blank" rel="noreferrer">Hermes Agent</a></li><li>评测：<a href="https://tokenmix.ai/blog/hermes-agent-review-self-improving-open-source-2026" target="_blank" rel="noreferrer">TokenMix Review</a></li></ul>',31)])])}const c=t(l,[["render",n]]);export{m as __pageData,c as default};
